  1→import React, { useEffect, useState } from 'react';
  2→import { Circle, MapContainer, Marker, Popup, TileLayer, useMap } from 'react-leaflet';
  3→import L from 'leaflet';
  4→import { Category, DataPoint } from '../../types';
  5→import type { MapScope } from '../../shared/types';
  6→import { LEGACY_CATEGORY_MAP, VERTICALS } from '../../shared/verticals';
  7→
  8→type MapPointGroup = {
  9→  key: string;
 10→  latitude: number;
 11→  longitude: number;
 12→  points: DataPoint[];
 13→};
 14→
 15→interface Props {
 16→  mapScope: MapScope;
 17→  mapCenter: [number, number];
 18→  mapZoom: number;
 19→  mapMinZoom: number;
 20→  mapBounds: [[number, number], [number, number]] | undefined;
 21→  mapPointGroups: MapPointGroup[];
 22→  selectedCityLabel: string;
 23→  onSelectPoint: (point: DataPoint) => void;
 24→  categoryLabel: (type: Category) => string;
 25→  formatExplorerPrimaryMeta: (point: DataPoint) => string;
 26→  formatPharmacyOpenStatus: (point: DataPoint) => string | null;
 27→  language: 'en' | 'fr';
 28→  t: (en: string, fr: string) => string;
 29→  isLowEndDevice: boolean;
 30→}
 31→
 32→const createMarkerIcon = (color: string) =>
 33→  L.divIcon({
 34→    className: '',
 35→    html: `<div style="width:26px;height:26px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;"></div>`,
 36→    iconSize: [26, 26],
 37→    iconAnchor: [13, 13]
 38→  });
 39→
 40→const clusterIconCache = new Map<string, L.DivIcon>();
 41→
 42→const getClusterIcon = (color: string, count: number) => {
 43→  const key = `${color}_${count}`;
 44→  const cached = clusterIconCache.get(key);
 45→  if (cached) return cached;
 46→  const icon = L.divIcon({
 47→    className: '',
 48→    html: `<div style="min-width:28px;height:28px;padding:0 8px;border-radius:9999px;background:${color};border:2px solid #ffffff;box-shadow:0 8px 16px rgba(15,43,70,0.35);display:flex;align-items:center;justify-content:center;color:#ffffff;font-size:11px;font-weight:700;line-height:1;">${count}</div>`,
 49→    iconSize: [28, 28],
 50→    iconAnchor: [14, 14]
 51→  });
 52→  clusterIconCache.set(key, icon);
 53→  return icon;
 54→};
 55→
 56→const markerIconCache = new Map<string, L.DivIcon>();
 57→
 58→const getMarkerIconForType = (type: Category): L.DivIcon => {
 59→  const verticalId = LEGACY_CATEGORY_MAP[type] ?? type;
 60→  const color = VERTICALS[verticalId]?.color ?? '#374151';
 61→  const cached = markerIconCache.get(color);
 62→  if (cached) return cached;
 63→  const icon = createMarkerIcon(color);
 64→  markerIconCache.set(color, icon);
 65→  return icon;
 66→};
 67→
 68→const agentLocationIcon = L.divIcon({
 69→  className: '',
 70→  html: `<div style="width:16px;height:16px;border-radius:9999px;background:#3b82f6;border:3px solid #ffffff;box-shadow:0 0 0 2px rgba(59,130,246,0.3),0 2px 8px rgba(0,0,0,0.2);"></div>`,
 71→  iconSize: [16, 16],
 72→  iconAnchor: [8, 8]
 73→});
 74→
 75→const AgentLocationMarker: React.FC = () => {
 76→  const [position, setPosition] = useState<{ lat: number; lng: number; accuracy: number } | null>(null);
 77→
 78→  useEffect(() => {
 79→    if (!navigator.geolocation) return;
 80→    const watchId = navigator.geolocation.watchPosition(
 81→      (pos) => setPosition({ lat: pos.coords.latitude, lng: pos.coords.longitude, accuracy: pos.coords.accuracy }),
 82→      () => {},
 83→      { enableHighAccuracy: true, maximumAge: 10000, timeout: 15000 }
 84→    );
 85→    return () => navigator.geolocation.clearWatch(watchId);
 86→  }, []);
 87→
 88→  if (!position) return null;
 89→
 90→  return (
 91→    <>
 92→      <Circle
 93→        center={[position.lat, position.lng]}
 94→        radius={Math.min(position.accuracy, 200)}
 95→        pathOptions={{ color: '#3b82f6', fillColor: '#3b82f6', fillOpacity: 0.1, weight: 1 }}
 96→      />
 97→      <Marker position={[position.lat, position.lng]} icon={agentLocationIcon} zIndexOffset={1000}>
 98→        <Popup>
 99→          <span className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">Your location</span>
100→        </Popup>
101→      </Marker>
102→    </>
103→  );
104→};
105→
106→const MapSizeSync: React.FC<{ active: boolean }> = ({ active }) => {
107→  const map = useMap();
108→
109→  useEffect(() => {
110→    if (!active) return;
111→    const rafId = requestAnimationFrame(() => {
112→      map.invalidateSize({ animate: false });
113→    });
114→    const timeoutId = window.setTimeout(() => {
115→      map.invalidateSize({ animate: false });
116→    }, 140);
117→
118→    return () => {
119→      cancelAnimationFrame(rafId);
120→      window.clearTimeout(timeoutId);
121→    };
122→  }, [active, map]);
123→
124→  return null;
125→};
126→
127→const HomeMap: React.FC<Props> = ({
128→  mapScope,
129→  mapCenter,
130→  mapZoom,
131→  mapMinZoom,
132→  mapBounds,
133→  mapPointGroups,
134→  selectedCityLabel,
135→  onSelectPoint,
136→  categoryLabel,
137→  formatExplorerPrimaryMeta,
138→  formatPharmacyOpenStatus,
139→  language,
140→  t,
141→  isLowEndDevice
142→}) => {
143→  return (
144→    <div className="flex-1 bg-[#e7eef4] relative overflow-hidden z-0 min-h-0">
145→      <MapContainer
146→        key={`map-${mapScope}`}
147→        center={mapCenter}
148→        zoom={mapZoom}
149→        minZoom={mapMinZoom}
150→        maxBounds={mapBounds}
151→        maxBoundsViscosity={mapBounds ? 1.0 : undefined}
152→        scrollWheelZoom
153→        preferCanvas={isLowEndDevice}
154→        zoomAnimation={!isLowEndDevice}
155→        fadeAnimation={!isLowEndDevice}
156→        markerZoomAnimation={!isLowEndDevice}
157→        className="absolute inset-0 h-full w-full"
158→      >
159→        <MapSizeSync active />
160→        <AgentLocationMarker />
161→        <TileLayer
162→          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
163→          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
164→        />
165→        {mapPointGroups.map((group) => {
166→          const singlePoint = group.points.length === 1 ? group.points[0] : null;
167→          const icon = singlePoint
168→            ? getMarkerIconForType(singlePoint.type)
169→            : (() => {
170→              const types = new Set(group.points.map((p) => LEGACY_CATEGORY_MAP[p.type] ?? p.type));
171→              const color = types.size === 1
172→                ? (VERTICALS[Array.from(types)[0]]?.color ?? '#c86b4a')
173→                : '#c86b4a';
174→              return getClusterIcon(color, group.points.length);
175→            })();
176→
177→          return (
178→            <Marker
179→              key={group.key}
180→              position={[group.latitude, group.longitude]}
181→              icon={icon}
182→            >
183→              <Popup>
184→                {singlePoint ? (
185→                  <div className="space-y-1">
186→                    <span className="text-[9px] font-bold uppercase tracking-widest text-[#0f2b46]">
187→                      {categoryLabel(singlePoint.type)}
188→                    </span>
189→                    <p className="text-sm font-semibold text-gray-900">{singlePoint.name}</p>
190→                    <p className="text-[10px] text-gray-600">{formatExplorerPrimaryMeta(singlePoint)}</p>
191→                    {singlePoint.type === Category.PHARMACY && (
192→                      <p className="text-[10px] text-gray-500">{formatPharmacyOpenStatus(singlePoint)}</p>
193→                    )}
194→                    <button
195→                      className="mt-2 w-full rounded-lg bg-[#0f2b46] px-2 py-1 text-[10px] font-bold uppercase tracking-widest text-white"
196→                      onClick={() => onSelectPoint(singlePoint)}
197→                    >
198→                      {t('View Details', 'Voir details')}
199→                    </button>
200→                  </div>
201→                ) : (
202→                  <div className="space-y-2 min-w-[220px]">
203→                    <p className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
204→                      {language === 'fr' ? `${group.points.length} points au meme endroit` : `${group.points.length} points at this location`}
205→                    </p>
206→                    <div className="space-y-1.5">
207→                      {group.points.map((point) => (
208→                        <button
209→                          key={point.id}
210→                          className="w-full rounded-lg border border-gray-100 px-2 py-1.5 text-left hover:bg-gray-50"
211→                          onClick={() => onSelectPoint(point)}
212→                        >
213→                          <p className="text-[11px] font-semibold text-gray-900 truncate">{point.name}</p>
214→                          <p className="text-[9px] uppercase tracking-wider text-gray-500">
215→                            {categoryLabel(point.type)}
216→                          </p>
217→                        </button>
218→                      ))}
219→                    </div>
220→                  </div>
221→                )}
222→              </Popup>
223→            </Marker>
224→          );
225→        })}
226→      </MapContainer>
227→      <div className="absolute inset-x-4 top-4 z-20 bg-white/95 backdrop-blur rounded-xl p-3 border border-gray-100 shadow-sm">
228→        <div className="flex items-center justify-between">
229→          <div>
230→            <p className="text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
231→              {mapScope === 'bonamoussadi'
232→                ? t('Bonamoussadi Geofence', 'Geofence Bonamoussadi')
233→                : mapScope === 'cameroon'
234→                  ? t('Cameroon Coverage', 'Couverture Cameroun')
235→                  : t('Global Coverage', 'Couverture mondiale')}
236→            </p>
237→            <p className="text-xs text-gray-500">
238→              {mapScope === 'bonamoussadi' ? t('Map blocked to', 'Carte bloquee sur') : t('Map unlocked to', 'Carte debloquee sur')} {selectedCityLabel}
239→            </p>
240→          </div>
241→          <div className="w-2 h-2 rounded-full bg-[#4c7c59] animate-pulse"></div>
242→        </div>
243→      </div>
244→    </div>
245→  );
246→};
247→
248→export default HomeMap;
