  1→import React, { useEffect, useMemo, useState } from 'react';
  2→import {
  3→  AlertTriangle,
  4→  ArrowLeft,
  5→  Award,
  6→  BadgeCheck,
  7→  Calendar,
  8→  Gift,
  9→  MapPin,
 10→  Settings as SettingsIcon,
 11→  TrendingUp,
 12→  Trash2,
 13→  Wallet
 14→} from 'lucide-react';
 15→import { apiJson } from '../../lib/client/api';
 16→import { clearSyncErrorRecords, listSyncErrorRecords, type SyncErrorRecord } from '../../lib/client/offlineQueue';
 17→import type { CollectionAssignment, MapScope, PointEvent, UserProfile } from '../../shared/types';
 18→import { categoryLabel as getCategoryLabelFromRegistry } from '../../shared/verticals';
 19→import { getEffectiveEventXp } from '../../shared/xp';
 20→import BadgeGrid, { computeBadges } from '../BadgeSystem';
 21→
 22→interface Props {
 23→  onBack: () => void;
 24→  onSettings: () => void;
 25→  onRedeem: () => void;
 26→  onSubmissionQueue: () => void;
 27→  language: 'en' | 'fr';
 28→}
 29→
 30→const Profile: React.FC<Props> = ({ onBack, onSettings, onRedeem, onSubmissionQueue, language }) => {
 31→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 32→  const historyPreviewLimit = 5;
 33→  const [profile, setProfile] = useState<UserProfile | null>(null);
 34→  const [isLoading, setIsLoading] = useState(true);
 35→  const [loadError, setLoadError] = useState('');
 36→  const [userLocation, setUserLocation] = useState(t('Location not set', 'Position non definie'));
 37→  const [history, setHistory] = useState<Array<{ id: string; date: string; location: string; type: string; xp: number }>>([]);
 38→  const [showAllHistory, setShowAllHistory] = useState(false);
 39→  const [ownEvents, setOwnEvents] = useState<PointEvent[]>([]);
 40→  const [syncErrors, setSyncErrors] = useState<SyncErrorRecord[]>([]);
 41→  const [isLoadingSyncErrors, setIsLoadingSyncErrors] = useState(true);
 42→  const [isClearingSyncErrors, setIsClearingSyncErrors] = useState(false);
 43→  const [syncErrorActionError, setSyncErrorActionError] = useState('');
 44→  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
 45→  const [isLoadingAssignments, setIsLoadingAssignments] = useState(true);
 46→  const [assignmentError, setAssignmentError] = useState('');
 47→  const [isUpdatingAssignmentId, setIsUpdatingAssignmentId] = useState<string | null>(null);
 48→  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
 49→    if (isAdminMode) return 'global';
 50→    if (value === 'cameroon' || value === 'global') return value;
 51→    return 'bonamoussadi';
 52→  };
 53→  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
 54→  const isMapUnlocked = activeMapScope !== 'bonamoussadi';
 55→
 56→  const formatHistoryDate = (iso: string) => {
 57→    const date = new Date(iso);
 58→    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');
 59→
 60→    const now = new Date();
 61→    const sameDay = now.toDateString() === date.toDateString();
 62→    const yesterday = new Date(now);
 63→    yesterday.setDate(now.getDate() - 1);
 64→    const isYesterday = yesterday.toDateString() === date.toDateString();
 65→    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 66→
 67→    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
 68→    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
 69→    return `${date.toLocaleDateString([], { month: 'short', day: '2-digit' })} • ${time}`;
 70→  };
 71→
 72→  const submissionToHistory = (submission: PointEvent) => {
 73→    const details = (submission.details ?? {}) as Record<string, unknown>;
 74→    const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
 75→    const locationLabel = siteName || `GPS: ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
 76→    const typeLabel = getCategoryLabelFromRegistry(submission.category, language);
 77→    const xpAwarded = getEffectiveEventXp(submission);
 78→
 79→    return {
 80→      id: submission.id,
 81→      date: formatHistoryDate(submission.createdAt),
 82→      location: locationLabel,
 83→      type: typeLabel,
 84→      xp: xpAwarded
 85→    };
 86→  };
 87→
 88→  const categoryLabel = (category: SyncErrorRecord['payloadSummary']['category']) => {
 89→    return getCategoryLabelFromRegistry(category, language);
 90→  };
 91→
 92→  useEffect(() => {
 93→    const loadProfile = async () => {
 94→      try {
 95→        setIsLoading(true);
 96→        setLoadError('');
 97→        const data = await apiJson<UserProfile>('/api/user');
 98→        setProfile(data);
 99→        setShowAllHistory(false);
100→
101→        try {
102→          const userId = typeof data?.id === 'string' ? data.id.toLowerCase().trim() : '';
103→          const scope = normalizeMapScope(data?.mapScope, Boolean(data?.isAdmin));
104→          const params = new URLSearchParams({ view: 'events' });
105→          if (scope !== 'bonamoussadi') params.set('scope', scope);
106→          const submissions = await apiJson<PointEvent[]>(`/api/submissions?${params.toString()}`);
107→          if (!userId) {
108→            setHistory([]);
109→            setUserLocation(t('Location not set', 'Position non definie'));
110→            return;
111→          }
112→
113→          const ownSubmissions = (Array.isArray(submissions) ? submissions : [])
114→            .filter((submission) => (typeof submission.userId === 'string' ? submission.userId.toLowerCase().trim() : '') === userId)
115→            .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
116→
117→          setOwnEvents(ownSubmissions);
118→          const historyItems = ownSubmissions.map(submissionToHistory);
119→          setHistory(historyItems);
120→
121→          const latest = ownSubmissions[0];
122→          if (latest) {
123→            const details = (latest.details ?? {}) as Record<string, unknown>;
124→            const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
125→            setUserLocation(siteName || `GPS ${latest.location.latitude.toFixed(4)}°, ${latest.location.longitude.toFixed(4)}°`);
126→          } else {
127→            setUserLocation(t('No contributions yet', 'Pas encore de contributions'));
128→          }
129→        } catch {
130→          setHistory([]);
131→          setUserLocation(t('Location not set', 'Position non definie'));
132→        }
133→      } catch {
134→        setProfile(null);
135→        setLoadError(t('Unable to load profile.', 'Impossible de charger le profil.'));
136→        setHistory([]);
137→        setUserLocation(t('Location not set', 'Position non definie'));
138→      } finally {
139→        setIsLoading(false);
140→      }
141→    };
142→    loadProfile();
143→  }, [language]);
144→
145→  const badges = useMemo(() => computeBadges(ownEvents, language), [ownEvents, language]);
146→  const earnedBadgeCount = badges.filter((b) => b.earned).length;
147→  const nextBadge = badges.find((b) => !b.earned);
148→
149→  const pointsThisWeek = useMemo(() => {
150→    const now = new Date();
151→    const dayOfWeek = now.getDay();
152→    const mondayOffset = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
153→    const monday = new Date(now.getFullYear(), now.getMonth(), now.getDate() - mondayOffset);
154→    const mondayKey = `${monday.getFullYear()}-${String(monday.getMonth() + 1).padStart(2, '0')}-${String(monday.getDate()).padStart(2, '0')}`;
155→    return ownEvents.filter((e) => e.createdAt.slice(0, 10) >= mondayKey).length;
156→  }, [ownEvents]);
157→
158→  const visibleHistory = showAllHistory ? history : history.slice(0, historyPreviewLimit);
159→  const canToggleHistory = history.length > historyPreviewLimit;
160→
161→  useEffect(() => {
162→    let cancelled = false;
163→
164→    const loadAssignments = async () => {
165→      try {
166→        setIsLoadingAssignments(true);
167→        setAssignmentError('');
168→        const data = await apiJson<CollectionAssignment[]>('/api/user?view=assignments');
169→        if (cancelled) return;
170→        setAssignments(Array.isArray(data) ? data : []);
171→      } catch (error) {
172→        if (cancelled) return;
173→        const message =
174→          error instanceof Error
175→            ? error.message
176→            : t('Unable to load assignments.', 'Impossible de charger les affectations.');
177→        setAssignmentError(message);
178→        setAssignments([]);
179→      } finally {
180→        if (!cancelled) setIsLoadingAssignments(false);
181→      }
182→    };
183→
184→    void loadAssignments();
185→    return () => {
186→      cancelled = true;
187→    };
188→  }, [language]);
189→
190→  useEffect(() => {
191→    let cancelled = false;
192→
193→    const loadSyncErrors = async () => {
194→      try {
195→        setIsLoadingSyncErrors(true);
196→        const records = await listSyncErrorRecords();
197→        if (!cancelled) setSyncErrors(records);
198→      } catch {
199→        if (!cancelled) setSyncErrors([]);
200→      } finally {
201→        if (!cancelled) setIsLoadingSyncErrors(false);
202→      }
203→    };
204→
205→    void loadSyncErrors();
206→    return () => {
207→      cancelled = true;
208→    };
209→  }, []);
210→
211→  const handleClearSyncErrors = async () => {
212→    if (isClearingSyncErrors) return;
213→    setSyncErrorActionError('');
214→    try {
215→      setIsClearingSyncErrors(true);
216→      await clearSyncErrorRecords();
217→      setSyncErrors([]);
218→    } catch {
219→      setSyncErrorActionError(t('Unable to clear sync errors.', 'Impossible d\'effacer les erreurs de synchronisation.'));
220→    } finally {
221→      setIsClearingSyncErrors(false);
222→    }
223→  };
224→
225→  const handleAssignmentStatus = async (assignmentId: string, status: CollectionAssignment['status']) => {
226→    if (isUpdatingAssignmentId) return;
227→    setAssignmentError('');
228→    try {
229→      setIsUpdatingAssignmentId(assignmentId);
230→      const updated = await apiJson<CollectionAssignment>('/api/user?view=assignments', {
231→        method: 'PATCH',
232→        headers: { 'Content-Type': 'application/json' },
233→        body: JSON.stringify({ id: assignmentId, status }),
234→      });
235→      setAssignments((prev) => prev.map((assignment) => (assignment.id === assignmentId ? updated : assignment)));
236→    } catch (error) {
237→      const message =
238→        error instanceof Error
239→          ? error.message
240→          : t('Unable to update assignment.', 'Impossible de mettre a jour l\'affectation.');
241→      setAssignmentError(message);
242→    } finally {
243→      setIsUpdatingAssignmentId(null);
244→    }
245→  };
246→
247→  return (
248→    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
249→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
250→        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
251→          <ArrowLeft size={20} />
252→        </button>
253→        <h3 className="text-sm font-bold mx-auto">{t('Dashboard', 'Tableau de bord')}</h3>
254→        <button onClick={onSettings} className="p-2 text-[#0f2b46] absolute right-2">
255→          <SettingsIcon size={20} />
256→        </button>
257→      </div>
258→
259→      <div className="p-4 space-y-6">
260→        <div className="flex flex-col items-center py-4 text-center">
261→          <div className="relative mb-4">
262→            <div className="w-24 h-24 rounded-full border-4 border-white shadow-xl bg-[#e7eef4] overflow-hidden">
263→              <img src="https://picsum.photos/seed/jeanpaul/300/300" alt={t('avatar', 'avatar')} className="w-full h-full object-cover" />
264→            </div>
265→            <div className="absolute -bottom-1 -right-1 p-1 bg-[#4c7c59] rounded-full border-2 border-white">
266→              <BadgeCheck size={14} className="text-white" />
267→            </div>
268→          </div>
269→          <h2 className="text-xl font-bold text-gray-900">
270→            {isLoading ? (
271→              <span className="inline-block h-4 w-40 rounded-full bg-gray-200 animate-pulse"></span>
272→            ) : (
273→              profile?.name || profile?.phone || profile?.email || t('Contributor', 'Contributeur')
274→            )}
275→          </h2>
276→          {!isLoading && (
277→            <div className="flex items-center justify-center text-[10px] text-gray-400 mt-1 font-bold uppercase tracking-widest space-x-2">
278→              <MapPin size={12} />
279→              <span>{userLocation}</span>
280→            </div>
281→          )}
282→          {loadError && (
283→            <div className="mt-2 text-[10px] font-bold uppercase tracking-widest text-red-500">
284→              {loadError}
285→            </div>
286→          )}
